    def cyclic: Declaration     = apply("cyclic")
    def numeric: Declaration    = apply("numeric")
    def alphabetic: Declaration = apply("alphabetic")
    def symbolic: Declaration   = apply("symbolic")
    def fixed: Declaration      = apply("fixed")

  /** `<system-color>` — `AccentColor | AccentColorText | ActiveText | ButtonBorder | ButtonFace | ButtonText | Canvas |
    * CanvasText | Field | FieldText | GrayText | Highlight | HighlightText | LinkText | Mark | MarkText | SelectedItem |
    * SelectedI
    */
  trait SystemColor extends DS with DeprecatedColor:
    /** Background of accented user interface controls. */
    def AccentColor: Declaration = apply("AccentColor")

    /** Text of accented user interface controls. */
    def AccentColorText: Declaration = apply("AccentColorText")

    /** Text in active links. For light backgrounds, traditionally red. */
    def ActiveText: Declaration = apply("ActiveText")

    /** The base border color for push buttons. */
    def ButtonBorder: Declaration = apply("ButtonBorder")

    /** The face background color for push buttons. */
    def ButtonFace: Declaration = apply("ButtonFace")

    /** Text on push buttons. */
    def ButtonText: Declaration = apply("ButtonText")

    /** Background of application content or documents. */
    def Canvas: Declaration = apply("Canvas")

    /** Text in application content or documents. */
    def CanvasText: Declaration = apply("CanvasText")

    /** Background of input fields. */
    def Field: Declaration = apply("Field")

    /** Text in input fields. */
    def FieldText: Declaration = apply("FieldText")

    /** Disabled text. (Often, but not necessarily, gray.) */
    def GrayText: Declaration = apply("GrayText")

    /** Background of selected text, for example from ::selection. */
    def Highlight: Declaration = apply("Highlight")

    /** Text of selected text. */
    def HighlightText: Declaration = apply("HighlightText")

    /** Text in non-active, non-visited links. For light backgrounds, traditionally blue. */
    def LinkText: Declaration = apply("LinkText")

    /** Background of text that has been specially marked (such as by the HTML mark element). */
    def Mark: Declaration = apply("Mark")

    /** Text that has been specially marked (such as by the HTML mark element). */
    def MarkText: Declaration = apply("MarkText")

    /** Background of selected items, for example a selected checkbox. */
    def SelectedItem: Declaration = apply("SelectedItem")

    /** Text of selected items. */
    def SelectedItemText: Declaration = apply("SelectedItemText")

    /** Text in visited links. For light backgrounds, traditionally purple. */
    def VisitedText: Declaration = apply("VisitedText")
  end SystemColor

  /** `<layout-box>` — `<visual-box> | margin-box` */
  trait LayoutBox extends DS with VisualBox:
    /** Refers to the margin box or margin edge. (In an SVG context, treated as stroke-box.) */
    def marginBox: Declaration = apply("margin-box")

  /** `<historical-lig-values>` — `[ historical-ligatures | no-historical-ligatures ]` */
  trait HistoricalLigValues extends DS:
    def historicalLigatures: Declaration   = apply("historical-ligatures")
    def noHistoricalLigatures: Declaration = apply("no-historical-ligatures")

  /** `<baseline-metric>` —
    * `text-bottom | alphabetic | ideographic | middle | central | mathematical | hanging | text-top`
    */
  trait BaselineMetric extends DS with Auto:
    /** Use the text-under baselines. */
    def textBottom: Declaration = apply("text-bottom")

    /** Use the alphabetic baselines. */
    def alphabetic: Declaration = apply("alphabetic")

    /** Use the ideographic-under baselines. */
    def ideographic: Declaration = apply("ideographic")

    /** Use the x-middle baselines; except under text-orientation: upright (where the alphabetic and x-height baselines
      * are essentially meaningless) use the central baseline.
      */
    def middle: Declaration = apply("middle")

    /** Use the central baselines. */
    def central: Declaration = apply("central")

    /** Use the math baselines. */
    def mathematical: Declaration = apply("mathematical")

    /** Use the hanging baselines. */
    def hanging: Declaration = apply("hanging")

    /** Use the text-over baselines. */
    def textTop: Declaration = apply("text-top")
  end BaselineMetric

  /** `<bg-size>` — `[ <length-percentage [0,∞]> | auto ]{1,2} | cover | contain` */
  trait BgSize extends DS with Auto:
    def cover: Declaration   = apply("cover")
    def contain: Declaration = apply("contain")

  /** `<autospace>` — `no-autospace | [ ideograph-alpha || ideograph-numeric || punctuation ] || [ insert | replace ]`
    */
  trait Autospace extends DS:
    def noAutospace: Declaration      = apply("no-autospace")
    def ideographAlpha: Declaration   = apply("ideograph-alpha")
    def ideographNumeric: Declaration = apply("ideograph-numeric")
    def punctuation: Declaration      = apply("punctuation")
    def insert: Declaration           = apply("insert")
    def replace: Declaration          = apply("replace")

  /** `<attr-modifier>` — `i | s` */
  trait AttrModifier extends DS:
    def i: Declaration = apply("i")
    def s: Declaration = apply("s")

  /** `<svg-paint>` — `child | child( <integer> )` */
  trait SvgPaint extends DS:
    /** Refers to the last child paint server element of the element being painted. If there is no such child, behaves
      * as none.
      */
    def child: Declaration = apply("child")

  /** `<text-edge>` —
    * `[ text | ideographic | ideographic-ink ] | [ text | ideographic | ideographic-ink | cap | ex ] [ text | ideographic | ideographic-ink | alphabetic ]`
    */
  trait TextEdge extends DS:
    /** Use the ascent/descent plus any positive half-leading. Margin/padding/border is ignored for the purpose of
      * sizing the line box.
      */
    def leading: Declaration = apply("leading")

    /** Use the text-over baseline/text-under baseline as the over/under edge. */
    def text: Declaration = apply("text")

    /** Use the cap-height baseline as the over edge. */
    def cap: Declaration = apply("cap")

    /** Use the ideographic-over baseline/ideographic-under baseline as the over/under edge. */
    def ideographic: Declaration = apply("ideographic")

    /** Use the ideographic-ink-over baseline/ideographic-ink-under baseline as the over/under edge. */
    def ideographicInk: Declaration = apply("ideographic-ink")

    /** Use the alphabetic baseline as the under edge. */
    def alphabetic: Declaration = apply("alphabetic")
  end TextEdge

  /** `<display-legacy>` — `inline-block | inline-table | inline-flex | inline-grid` */
  trait DisplayLegacy extends DS:
    /** Computes to inline flow-root. */
    def inlineBlock: Declaration = apply("inline-block")

    /** Computes to inline table. */
    def inlineTable: Declaration = apply("inline-table")

    /** Computes to inline flex. */
    def inlineFlex: Declaration = apply("inline-flex")

    /** Computes to inline grid. */
    def inlineGrid: Declaration = apply("inline-grid")
  end DisplayLegacy

  /** `<request-url-modifier>` — `<cross-origin-modifier> | <integrity-modifier> | <referrer-policy-modifier>` */
  trait RequestUrlModifier extends DS:
    /** <cross-origin-modifier> = cross-origin(anonymous | use-credentials) */
    def anonymous: Declaration = apply("anonymous")

    /** <cross-origin-modifier> = cross-origin(anonymous | use-credentials) */
    def useCredentials: Declaration = apply("use-credentials")

    /** <referrer-policy-modifier> = referrer-policy(no-referrer | no-referrer-when-downgrade | same-origin | origin |
      * strict-origin | origin-when-cross-origin | strict-origin-when-cross-origin | unsafe-url)
      */
    def noReferrer: Declaration = apply("no-referrer")

    /** <referrer-policy-modifier> = referrer-policy(no-referrer | no-referrer-when-downgrade | same-origin | origin |
      * strict-origin | origin-when-cross-origin | strict-origin-when-cross-origin | unsafe-url)
      */
    def noReferrerWhenDowngrade: Declaration = apply("no-referrer-when-downgrade")

    /** <referrer-policy-modifier> = referrer-policy(no-referrer | no-referrer-when-downgrade | same-origin | origin |
      * strict-origin | origin-when-cross-origin | strict-origin-when-cross-origin | unsafe-url)
      */
    def sameOrigin: Declaration = apply("same-origin")

    /** <referrer-policy-modifier> = referrer-policy(no-referrer | no-referrer-when-downgrade | same-origin | origin |
      * strict-origin | origin-when-cross-origin | strict-origin-when-cross-origin | unsafe-url)
      */
    def origin: Declaration = apply("origin")

    /** <referrer-policy-modifier> = referrer-policy(no-referrer | no-referrer-when-downgrade | same-origin | origin |
      * strict-origin | origin-when-cross-origin | strict-origin-when-cross-origin | unsafe-url)
      */
    def strictOrigin: Declaration = apply("strict-origin")

    /** <referrer-policy-modifier> = referrer-policy(no-referrer | no-referrer-when-downgrade | same-origin | origin |
      * strict-origin | origin-when-cross-origin | strict-origin-when-cross-origin | unsafe-url)
      */
    def originWhenCrossOrigin: Declaration = apply("origin-when-cross-origin")

    /** <referrer-policy-modifier> = referrer-policy(no-referrer | no-referrer-when-downgrade | same-origin | origin |
      * strict-origin | origin-when-cross-origin | strict-origin-when-cross-origin | unsafe-url)
      */
    def strictOriginWhenCrossOrigin: Declaration = apply("strict-origin-when-cross-origin")

    /** <referrer-policy-modifier> = referrer-policy(no-referrer | no-referrer-when-downgrade | same-origin | origin |
      * strict-origin | origin-when-cross-origin | strict-origin-when-cross-origin | unsafe-url)
      */
    def unsafeUrl: Declaration = apply("unsafe-url")
  end RequestUrlModifier

  /** `<boolean-expr>` —
    * `not <boolean-expr-group> | <boolean-expr-group> [ [ and <boolean-expr-group> ]* | [ or <boolean-expr-group> ]* ]`
    */
  trait BooleanExpr extends DS:
    def not: Declaration = apply("not")
    def and: Declaration = apply("and")
    def or: Declaration  = apply("or")

  /** `<xyz-space>` — `xyz | xyz-d50 | xyz-d65` */
  trait XyzSpace extends DS:
    def xyz: Declaration    = apply("xyz")
    def xyzD50: Declaration = apply("xyz-d50")
    def xyzD65: Declaration = apply("xyz-d65")

  /** `<step-easing-function>` — `step-start | step-end | <steps()>` */
  trait StepEasingFunction extends DS:
    def stepStart: Declaration = apply("step-start")
    def stepEnd: Declaration   = apply("step-end")

  /** `<discretionary-lig-values>` — `[ discretionary-ligatures | no-discretionary-ligatures ]` */
  trait DiscretionaryLigValues extends DS:
    def discretionaryLigatures: Declaration   = apply("discretionary-ligatures")
    def noDiscretionaryLigatures: Declaration = apply("no-discretionary-ligatures")

  /** `<overflow-position>` — `unsafe | safe` */
  trait OverflowPosition extends DS:
    /** If the size of the alignment subject overflows the alignment container, the alignment subject is instead aligned
      * as if the alignment mode were flex-start.
      */
    def safe: Declaration = apply("safe")

    /** Regardless of the relative sizes of the alignment subject and alignment container, the given alignment value is
      * honored.
      */
    def unsafe: Declaration = apply("unsafe")
  end OverflowPosition

  /** `<masking-mode>` — `alpha | luminance | match-source` */
  trait MaskingMode extends DS:
    def alpha: Declaration       = apply("alpha")
    def luminance: Declaration   = apply("luminance")
    def matchSource: Declaration = apply("match-source")

  /** `<content-level>` — `element | content | text | <attr()> | <counter>` */
  trait ContentLevel extends DS:
    def element: Declaration = apply("element")
    def content: Declaration = apply("content")
    def text: Declaration    = apply("text")
end StylesValueTraits
